<template>

 <!-- ==============================================
    ** Inner Banner **
    =================================================== -->
    <div class="inner-banner blog">
    <div class="container">
      <div class="row">
        <div class="col-sm-12">
          <div class="content">
            <h1>HISTORIA DE LA CARRERA</h1>
          </div>

          <h4>
                  <router-link to="/">INICIO</router-link>
                </h4>
       
        </div>
      </div>
    </div>
  </div>

  <!-- ==============================================
    ** Blog Detail **
    =================================================== -->
  <div class="container blog-wrapper padding-lg">
    
    <div class="row">
      <!-- Start Left Column -->
      <div class="col-sm-8 blog-left">
        <p class="content left-aligned" v-html="Institucion.institucion_historia"></p>
      </div>
      <!-- End Left Column -->

      <!-- Start Right Column -->
      <div class="col-sm-4">
        <sidebar-custom></sidebar-custom>
      </div>
      <!-- End Right Column -->
    </div>
  </div>

</template>

<style scoped>
.text-wrap {
    text-align: justify;
    padding: 0 70px;
}

h4 {
    margin-top: 5px;
    font-size: 15px;
}

p {
    margin-bottom: 5px;
}

.image-container {
  width: 100%;
  height: 300px;
  overflow: hidden;
}

.thumbnail-img {
  width: 100%;
  height: 100%;
  object-fit: cover;
}

.bg-overlay-img {
  background-image: url("@/assets/Fondo2.jpg");
}

.active-link {
    background: #540000;
  }

</style>


<script>
import { mapState } from "vuex";
import SidebarCustom from "@/components/SidebarCustom.vue";

export default {
  name: "AboutView",
  data() {
    return {
      Conv: [],
      Cur: [],
      Serv: [],
      Ofer: [],

      NUM_RESULTS: 3,
      pag: 1,
      pager: 0,
    };
  },
  computed: {
    ...mapState(["Institucion", "url_api"]),
  },
components: {
  SidebarCustom,
},
  methods: {
    async getConvocatoriasAll() {
      try {
        let res = await this.axios.get(
          "/api/convocatoriasAll/" + process.env.VUE_APP_ID_CARRERA
        );
        this.Conv = res.data;
        this.pager = this.Institucion.autoridad.length / this.NUM_RESULTS;
        if (this.pager - Math.trunc(this.pager) > 0) {
          this.pager = Math.trunc(this.pager) + 1;
        }
      } catch (error) {
        console.log(error);
      }
    },
    async getCursosAll() {
      try {
        let res = await this.axios.get(
          "/api/cursosAll/" + process.env.VUE_APP_ID_CARRERA
        );
        this.Cur = res.data;
      } catch (error) {
        console.log(error);
      }
    },
    async getServiciosAll() {
      try {
        let res = await this.axios.get(
          "/api/ServicioAll/" + process.env.VUE_APP_ID_CARRERA
        );
        this.Serv = res.data;
      } catch (error) {
        console.log(error);
      }
    },
    async getOfertasAll() {
      try {
        let res = await this.axios.get(
          "/api/OfertasAcademicasAll/" + process.env.VUE_APP_ID_CARRERA
        );
        this.Ofer = res.data;
        this.$store.commit("loading");
      } catch (error) {
        console.log(error);
      }
    },
  },
  created() {
    this.$store.commit("loadOn");
    this.getConvocatoriasAll();
    this.getCursosAll();
    this.getServiciosAll();
    this.getOfertasAll();
  },
};
</script>
